  .replace(/(draw.*?snake.*?\{[\s\S]*?)(ctx\.fillRect\([^;]+;)/m, `$1// smooth movement will be handled by interpolation\n$2`)
  .replace(/(const\s+CELL_SIZE\s*=\s*\d+;?)/, `$1\nconst ANIM_DURATION = 120;`)
  .replace(/(let\s+snake\s*=\s*\[[\s\S]*?\];)/, `$1\nlet visualSnake = snake.map(p => ({ ...p }));\nlet moveAnimation = null;`)
  .replace(/(function\s+gameTick\s*\(\)\s*\{[\s\S]*?)(snake\.unshift\([\s\S]*?\);\s*snake\.pop\(\);)/m,
`$1
const head = { ...snake[0] };
const next = { x: head.x + dir.x, y: head.y + dir.y };
snake.unshift(next);
snake.pop();
moveAnimation = { from: head, to: next, start: performance.now() };
`)
  .replace(/(function\s+render\(\)\s*\{[\s\S]*?)(drawSnake\(\);)/m, `$1
if (moveAnimation) {
  const t = Math.min(1, (performance.now() - moveAnimation.start) / ANIM_DURATION);
  const ease = t * (2 - t);
  visualSnake = snake.map((seg, i) => {
    if (i === 0) return {
      x: moveAnimation.from.x + (moveAnimation.to.x - moveAnimation.from.x) * ease,
      y: moveAnimation.from.y + (moveAnimation.to.y - moveAnimation.from.y) * ease
    };
    const prev = snake[i - 1];
    return {
      x: prev.x,
      y: prev.y
    };
  });
  if (t >= 1) moveAnimation = null;
} else {
  visualSnake = snake.map(p => ({ ...p }));
}
$2`)
