const widget = await space.current.readWidget("snake-game");
const src = widget.source || widget.content || widget.code || widget;
let text = typeof src === "string" ? src : JSON.stringify(src, null, 2);

const styleInsert = `
background: linear-gradient(180deg, #7fbf4d 0%, #5f9f3a 100%);
color: #1f2b17;
font-family: "Courier New", monospace;
text-shadow: 0 1px 0 rgba(255,255,255,0.25);
`;

let updated = text;

if (/style\s*[:=]\s*['"`][^'"`]*['"`]/.test(updated)) {
  updated = updated.replace(/style\s*[:=]\s*['"`]([^'"`]*)['"`]/, (m, p1) => {
    const merged = p1.includes("background") ? p1 : `${p1}; ${styleInsert}`;
    return m.replace(p1, merged);
  });
} else if (/className\s*[:=]\s*['"`][^'"`]*['"`]/.test(updated)) {
  updated = updated.replace(/className\s*[:=]\s*['"`]([^'"`]*)['"`]/, (m, p1) => {
    return m.replace(p1, `${p1} nokia-green`);
  });
} else if (/<(div|main|section|canvas|svg)(\s|>)/i.test(updated)) {
  updated = updated.replace(/<(div|main|section|canvas|svg)(\s|>)/i, `<$1 style="${styleInsert}"$2`);
} else {
  updated = `/* Nokia-style green background */\n${updated}\n`;
}

return await space.current.patchWidget("snake-game", { edits: [{ type: "replace", value: updated }] });

